using System.Collections.Generic;
using System.IO;
using System.Linq;
using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;
using UnityEngine.Rendering;
using UnityEngine.Rendering.Universal;

/// <summary>
/// Builds the static isometric clay diorama: a roofless 2x2 building with four
/// rooms (VR bedroom / robot assembly / science lab / storage warehouse).
/// Architecture is procedural primitives; hero assets are Blender FBX files
/// under Assets/Models (generated by BlenderPipeline/gen_*.py).
///
/// Layout (top view, camera sits SW looking NE):
///   NW = Bedroom     NE = Assembly
///   SW = Lab         SE = Storage
/// </summary>
public static class IsometricWorldBuilder
{
    const string ScenePath = "Assets/Scenes/IsometricWorld.unity";

    const float WallH = 3.0f;      // exterior/interior wall height
    const float ExtT = 0.35f;      // exterior wall thickness
    const float IntT = 0.30f;      // interior wall thickness
    const float Half = 12f;        // building outer half-extent
    const float CurbH = 0.28f;     // low curb on the open (S/W) sides
    const float DoorW = 1.8f, DoorH = 2.2f;

    static Material clay, clayFloor;
    static System.Random rng;

    // ------------------------------------------------------------ menu items

    [MenuItem("Tools/Isometric World/Build World")]
    public static void BuildWorld()
    {
        AssetDatabase.Refresh();
        rng = new System.Random(42);

        clay = EnsureMat("Assets/Materials/ClayMatte.mat", Hex("#E8EAF0"));
        clayFloor = EnsureMat("Assets/Materials/ClayFloor.mat", Hex("#DCE0EA"));
        EnsureSSAO("Assets/Settings/PC_Renderer.asset");
        EnsureSSAO("Assets/Settings/Mobile_Renderer.asset");
        ExtendShadowDistance("Assets/Settings/PC_RPAsset.asset");
        ExtendShadowDistance("Assets/Settings/Mobile_RPAsset.asset");

        var scene = EditorSceneManager.NewScene(NewSceneSetup.EmptyScene, NewSceneMode.Single);

        var root = new GameObject("IsometricWorld").transform;
        BuildArchitecture(Group("Architecture", root));
        BuildBedroom(Group("Bedroom", root));
        BuildLab(Group("Lab", root));
        BuildAssembly(Group("Assembly", root));
        BuildStorage(Group("Storage", root));
        BuildLightingAndCamera();

        Directory.CreateDirectory(Path.Combine(Application.dataPath, "Scenes"));
        EditorSceneManager.SaveScene(scene, ScenePath);
        AssetDatabase.SaveAssets();
        Debug.Log("[IsometricWorldBuilder] World built and saved to " + ScenePath);
    }

    [MenuItem("Tools/Isometric World/Render Screenshot")]
    public static void RenderScreenshot()
    {
        var cam = Camera.main;
        if (cam == null) cam = Object.FindFirstObjectByType<Camera>();
        if (cam == null) { Debug.LogError("No camera in scene - build the world first."); return; }

        const int w = 1920, h = 1080;
        var rt = new RenderTexture(w, h, 24, RenderTextureFormat.ARGB32);
        var prevTarget = cam.targetTexture;

        var request = new RenderPipeline.StandardRequest();
        if (RenderPipeline.SupportsRenderRequest(cam, request))
        {
            request.destination = rt;
            RenderPipeline.SubmitRenderRequest(cam, request);
        }
        else
        {
            cam.targetTexture = rt;
            cam.Render();
        }

        var prevActive = RenderTexture.active;
        RenderTexture.active = rt;
        var tex = new Texture2D(w, h, TextureFormat.RGB24, false);
        tex.ReadPixels(new Rect(0, 0, w, h), 0, 0);
        tex.Apply();
        RenderTexture.active = prevActive;
        cam.targetTexture = prevTarget;

        string dir = Path.Combine(Directory.GetParent(Application.dataPath).FullName, "Screenshots");
        Directory.CreateDirectory(dir);
        string path = Path.Combine(dir, "iso_world.png");
        File.WriteAllBytes(path, tex.EncodeToPNG());
        Object.DestroyImmediate(tex);
        rt.Release();
        Object.DestroyImmediate(rt);
        Debug.Log("[IsometricWorldBuilder] Screenshot saved to " + path);
    }

    /// <summary>Batch-mode entry: -executeMethod IsometricWorldBuilder.BuildAndScreenshotBatch</summary>
    public static void BuildAndScreenshotBatch()
    {
        BuildWorld();
        RenderScreenshot();
    }

    /// <summary>Diagnostic: open the saved scene and render a plain top-down plan view.</summary>
    public static void RenderTopDownBatch()
    {
        EditorSceneManager.OpenScene(ScenePath, OpenSceneMode.Single);
        var camGo = new GameObject("TopCam");
        var cam = camGo.AddComponent<Camera>();
        cam.orthographic = true;
        cam.orthographicSize = 13.5f;
        cam.clearFlags = CameraClearFlags.SolidColor;
        cam.backgroundColor = Hex("#E7EBF2");
        cam.transform.position = new Vector3(0, 60, 0);
        cam.transform.rotation = Quaternion.Euler(90, 0, 0);

        const int w = 1400, h = 1400;
        var rt = new RenderTexture(w, h, 24);
        cam.targetTexture = rt;
        cam.Render();
        RenderTexture.active = rt;
        var tex = new Texture2D(w, h, TextureFormat.RGB24, false);
        tex.ReadPixels(new Rect(0, 0, w, h), 0, 0);
        tex.Apply();
        string dir = Path.Combine(Directory.GetParent(Application.dataPath).FullName, "Screenshots");
        Directory.CreateDirectory(dir);
        File.WriteAllBytes(Path.Combine(dir, "iso_topdown.png"), tex.EncodeToPNG());
        Debug.Log("[IsometricWorldBuilder] Top-down saved.");
    }

    // ---------------------------------------------------------- architecture

    struct Opening { public float center, width, bottom, top;
        public Opening(float c, float w, float b, float t) { center = c; width = w; bottom = b; top = t; } }

    static void BuildArchitecture(Transform parent)
    {
        // floor slab with apron extending past the walls
        Box(parent, "FloorSlab", new Vector3(0, -0.2f, 0), new Vector3(Half * 2 + 1.8f, 0.4f, Half * 2 + 1.8f), clayFloor);

        var win = new Opening(-6.2f, 2.4f, 0.95f, 2.5f);   // bedroom window (N wall)
        var doorNS1 = new Opening(6f, DoorW, 0, DoorH);     // x=0 wall: bedroom <-> assembly
        var doorNS2 = new Opening(-6f, DoorW, 0, DoorH);    // x=0 wall: lab <-> storage
        var doorEW1 = new Opening(-6f, DoorW, 0, DoorH);    // z=0 wall: bedroom <-> lab
        var doorEW2 = new Opening(9.7f, DoorW, 0, DoorH);   // z=0 wall: assembly <-> storage

        // exterior: N + E full height, S + W low curbs (open toward camera)
        StraightWall(parent, "Wall_N", true, Half - ExtT / 2, -Half, Half, WallH, ExtT, new[] { win });
        StraightWall(parent, "Wall_E", false, Half - ExtT / 2, -Half, Half - ExtT, WallH, ExtT, null);
        StraightWall(parent, "Curb_S", true, -Half + ExtT / 2, -Half, Half, CurbH, ExtT, null);
        StraightWall(parent, "Curb_W", false, -Half + ExtT / 2, -Half + ExtT, Half - ExtT, CurbH, ExtT, null);

        // interior cross walls
        float inner = Half - ExtT;
        StraightWall(parent, "Wall_Mid_NS", false, 0, -inner, inner, WallH, IntT, new[] { doorNS1, doorNS2 });
        StraightWall(parent, "Wall_Mid_EW", true, 0, -inner, inner, WallH, IntT, new[] { doorEW1, doorEW2 });

        // open door leafs at two doorways
        DoorLeaf(parent, new Vector3(-IntT / 2f, 0, 6f - DoorW / 2f), 70f);    // bedroom<->assembly
        DoorLeaf(parent, new Vector3(-6f - DoorW / 2f, 0, IntT / 2f), -65f, true); // bedroom<->lab
    }

    /// <summary>Axis-aligned wall with rectangular openings (doors/windows).</summary>
    static void StraightWall(Transform parent, string name, bool alongX, float fixedCoord,
                             float from, float to, float height, float thick, Opening[] openings)
    {
        var wall = Group(name, parent);
        var opens = (openings ?? new Opening[0]).OrderBy(o => o.center).ToList();

        float cursor = from;
        foreach (var o in opens)
        {
            float a = o.center - o.width / 2, b = o.center + o.width / 2;
            if (a > cursor) Seg(wall, alongX, fixedCoord, cursor, a, 0, height, thick);
            if (o.bottom > 0.01f) Seg(wall, alongX, fixedCoord, a, b, 0, o.bottom, thick);       // sill
            if (o.top < height - 0.01f) Seg(wall, alongX, fixedCoord, a, b, o.top, height, thick); // header
            cursor = b;
        }
        if (cursor < to) Seg(wall, alongX, fixedCoord, cursor, to, 0, height, thick);
    }

    static void Seg(Transform parent, bool alongX, float fixedCoord, float from, float to,
                    float y0, float y1, float thick)
    {
        float len = to - from, mid = (from + to) / 2;
        Vector3 center = alongX ? new Vector3(mid, (y0 + y1) / 2, fixedCoord)
                                : new Vector3(fixedCoord, (y0 + y1) / 2, mid);
        Vector3 size = alongX ? new Vector3(len, y1 - y0, thick)
                              : new Vector3(thick, y1 - y0, len);
        Box(parent, "Seg", center, size, clay);
    }

    static void DoorLeaf(Transform parent, Vector3 hinge, float openAngle, bool alongX = false)
    {
        var pivot = new GameObject("DoorLeaf").transform;
        pivot.SetParent(parent, false);
        pivot.position = hinge;
        pivot.rotation = Quaternion.Euler(0, (alongX ? 90f : 0f) + openAngle, 0);
        Box(pivot, "Leaf", new Vector3(0, DoorH / 2 - 0.02f, DoorW / 2 - 0.03f),
            new Vector3(0.06f, DoorH - 0.06f, DoorW - 0.1f), clay);
    }

