               new Vector3(0.55f, 0.5f, 0.42f));                                  // nightstand
        Place(parent, "Furniture/floor_lamp", new Vector3(-11.15f, 0, 9.15f), 0);

        // desk / study run along the N wall
        Place(parent, "Furniture/desk", new Vector3(-3.0f, 0, 11.0f), 180);
        Place(parent, "Furniture/monitor_keyboard", new Vector3(-3.0f, 0.76f, 11.05f), 180);
        Place(parent, "Furniture/pc_tower", new Vector3(-1.8f, 0, 11.2f), 180);
        Place(parent, "Furniture/office_chair", new Vector3(-3.1f, 0, 10.05f), 10);
