        Place(parent, "Furniture/coffee_table", new Vector3(-9.15f, 0, 6.45f), 0);

        Cylinder(parent, "Rug", new Vector3(-6.1f, 0.02f, 5.4f),
                 new Vector3(4.8f, 0.02f, 3.4f), clay);   // lighter tone than floor

