    static void BuildStorage(Transform parent)
    {
        // shelves along the E wall, the N + W interior walls, and centre rows
        var shelfSpots = new List<(Vector3 pos, float rot)>
        {
            (new Vector3(11.3f, 0, -2.6f), 90), (new Vector3(11.3f, 0, -4.85f), 90),
            (new Vector3(11.3f, 0, -7.1f), 90),
            (new Vector3(2.9f, 0, -0.6f), 0), (new Vector3(5.1f, 0, -0.6f), 0),
            (new Vector3(4.6f, 0, -5.9f), 0), (new Vector3(6.7f, 0, -5.9f), 0),
            (new Vector3(0.75f, 0, -3.2f), -90), (new Vector3(0.75f, 0, -5.55f), -90),
        };
        foreach (var (pos, rot) in shelfSpots)
        {
            Place(parent, "Furniture/shelf_unit", pos, rot);
            FillShelf(parent, pos, rot);
        }

        Place(parent, "Furniture/pallet", new Vector3(9.7f, 0, -9.9f), 8);
        BoxStack(parent, new Vector3(9.7f, 0.16f, -9.9f), 8, 3);
        Place(parent, "Furniture/pallet", new Vector3(2.7f, 0, -8.3f), -6);
        Place(parent, "Furniture/barrel", new Vector3(2.5f, 0.16f, -8.45f), 0);
        Place(parent, "Furniture/barrel", new Vector3(3.0f, 0.16f, -8.05f), 0);

        Scaled(parent, "Furniture/unit_box_beveled", new Vector3(2.2f, 0, -4.4f), -8,
               new Vector3(0.68f, 0.6f, 0.68f));
        Scaled(parent, "Furniture/unit_box_beveled", new Vector3(2.28f, 0.6f, -4.32f), 14,
               new Vector3(0.45f, 0.42f, 0.45f));

        // loose crates scattered on the floor
        Place(parent, "Furniture/crate", new Vector3(5.6f, 0, -10.6f), 10);
        Place(parent, "Furniture/crate", new Vector3(6.3f, 0, -10.3f), -14);
        Place(parent, "Furniture/crate", new Vector3(5.95f, 0.62f, -10.45f), 4);
        Place(parent, "Furniture/crate", new Vector3(3.6f, 0, -10.7f), 22);

        // the humanoid robot carries a crate toward the assembly doorway (x=9.7, z=0)
        Place(parent, "Robots/robot_humanoid_carrying", new Vector3(9.0f, 0, -3.4f), 4);
        Plant(parent, new Vector3(11.2f, 0, -11.0f));
    }

    /// <summary>Scatter beveled boxes on the shelf levels of a shelf_unit.</summary>
    static void FillShelf(Transform parent, Vector3 unitPos, float rotY)
    {
        float[] levels = { 0.122f, 0.822f, 1.522f };
        var rot = Quaternion.Euler(0, rotY, 0);
        foreach (float y in levels)
        {
            int n = rng.Next(2, 5);
            for (int i = 0; i < n; i++)
            {
                float s = 0.30f + (float)rng.NextDouble() * 0.22f;
                float x = -0.78f + i * (1.6f / Mathf.Max(n - 1, 1)) + (float)rng.NextDouble() * 0.12f - 0.06f;
                float zj = ((float)rng.NextDouble() - 0.5f) * 0.12f;
                Vector3 local = new Vector3(x, y, zj);
                Scaled(parent, "Furniture/unit_box_beveled", unitPos + rot * local,
                       rotY + rng.Next(-14, 14), new Vector3(s, s * (0.8f + (float)rng.NextDouble() * 0.4f), s));
            }
        }
    }

    static void BoxStack(Transform parent, Vector3 basePos, float rotY, int count)
    {
        float y = basePos.y;
        float s0 = 0.72f;
        for (int i = 0; i < count; i++)
        {
            float s = s0 - i * 0.16f;
            float h = s * 0.9f;
            Scaled(parent, "Furniture/unit_box_beveled",
                   new Vector3(basePos.x + ((float)rng.NextDouble() - 0.5f) * 0.08f, y,
                               basePos.z + ((float)rng.NextDouble() - 0.5f) * 0.08f),
                   rotY + rng.Next(-16, 16), new Vector3(s, h, s));
            y += h;
        }
    }

    static void Plant(Transform parent, Vector3 pos)
    {
        var g = Group("Plant", parent);
        Cylinder(g, "Pot", pos + new Vector3(0, 0.11f, 0), new Vector3(0.30f, 0.11f, 0.30f), clay);
        Cylinder(g, "Trunk", pos + new Vector3(0, 0.35f, 0), new Vector3(0.045f, 0.14f, 0.045f), clay);
        Sphere(g, "Canopy_a", pos + new Vector3(0, 0.66f, 0), 0.42f, clay);
        Sphere(g, "Canopy_b", pos + new Vector3(0.14f, 0.88f, 0.06f), 0.30f, clay);
        Sphere(g, "Canopy_c", pos + new Vector3(-0.13f, 0.84f, -0.08f), 0.26f, clay);
    }

    // ------------------------------------------------------ lighting/camera

    static void BuildLightingAndCamera()
    {
        var lightGo = new GameObject("Directional Light");
        var light = lightGo.AddComponent<Light>();
        light.type = LightType.Directional;
        light.intensity = 1.25f;
        light.color = Hex("#FFFDF7");
        light.shadows = LightShadows.Soft;
        light.shadowStrength = 0.72f;
        light.transform.rotation = Quaternion.Euler(50, 128, 0);

        RenderSettings.ambientMode = AmbientMode.Flat;
        RenderSettings.ambientLight = Hex("#9AA6BC");   // dimmer so form + AO read
        RenderSettings.fog = false;

        var camGo = new GameObject("Main Camera");
        camGo.tag = "MainCamera";
        var cam = camGo.AddComponent<Camera>();
        cam.orthographic = true;
        cam.orthographicSize = 10.5f;
        cam.nearClipPlane = 0.3f;
        cam.farClipPlane = 200f;
        cam.clearFlags = CameraClearFlags.SolidColor;
        cam.backgroundColor = Hex("#E7EBF2");
        camGo.AddComponent<UniversalAdditionalCameraData>().renderPostProcessing = true;

        var rot = Quaternion.Euler(35.264f, 45f, 0);
        camGo.transform.rotation = rot;
        camGo.transform.position = new Vector3(0, 1f, 0) - rot * Vector3.forward * 42f;

        var controller = camGo.AddComponent<IsometricCameraController>();
        controller.defaultDistance = 42f;
        controller.maxOrthographicSize = 22f;
    }

    // ------------------------------------------------------------- plumbing

    static Transform Group(string name, Transform parent)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent, false);
        return go.transform;
    }

    static GameObject Box(Transform parent, string name, Vector3 center, Vector3 size, Material mat)
    {
        var go = GameObject.CreatePrimitive(PrimitiveType.Cube);
        go.name = name;
        go.transform.SetParent(parent, false);
        go.transform.position = center;
        go.transform.localScale = size;
        go.GetComponent<MeshRenderer>().sharedMaterial = mat;
        return go;
    }

    static GameObject Cylinder(Transform parent, string name, Vector3 center, Vector3 scale, Material mat)
    {
        var go = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
        go.name = name;
        go.transform.SetParent(parent, false);
        go.transform.position = center;
        go.transform.localScale = scale;
        go.GetComponent<MeshRenderer>().sharedMaterial = mat;
        return go;
    }

    static GameObject Sphere(Transform parent, string name, Vector3 center, float dia, Material mat)
    {
        var go = GameObject.CreatePrimitive(PrimitiveType.Sphere);
        go.name = name;
        go.transform.SetParent(parent, false);
        go.transform.position = center;
        go.transform.localScale = Vector3.one * dia;
        go.GetComponent<MeshRenderer>().sharedMaterial = mat;
        return go;
    }

    static GameObject Place(Transform parent, string modelPath, Vector3 pos, float rotY)
        => Scaled(parent, modelPath, pos, rotY, Vector3.one);

    // Places a prefab referenced by full asset path (e.g. an AI-generated robot prefab),
    // as opposed to Place/Scaled which resolve an FBX under Assets/Models/.
    static GameObject PlacePrefab(Transform parent, string assetPath, Vector3 pos, float rotY)
    {
        var prefab = AssetDatabase.LoadAssetAtPath<GameObject>(assetPath);
        if (prefab == null)
        {
            Debug.LogWarning("[IsometricWorldBuilder] Missing prefab: " + assetPath);
            return null;
        }
        var go = (GameObject)PrefabUtility.InstantiatePrefab(prefab, parent);
        go.transform.position = pos;
        go.transform.rotation = Quaternion.Euler(0, rotY, 0);
        go.transform.localScale = Vector3.one;
        foreach (var r in go.GetComponentsInChildren<MeshRenderer>())
        {
            var mats = new Material[r.sharedMaterials.Length];
            for (int i = 0; i < mats.Length; i++) mats[i] = clay;
            r.sharedMaterials = mats;
        }
        return go;
    }

    static GameObject Scaled(Transform parent, string modelPath, Vector3 pos, float rotY, Vector3 scale)
    {
        string assetPath = "Assets/Models/" + modelPath + ".fbx";
        var prefab = AssetDatabase.LoadAssetAtPath<GameObject>(assetPath);
        if (prefab == null)
        {
            Debug.LogWarning("[IsometricWorldBuilder] Missing model: " + assetPath);
            return null;
        }
        var go = (GameObject)PrefabUtility.InstantiatePrefab(prefab, parent);
        go.transform.position = pos;
        go.transform.rotation = Quaternion.Euler(0, rotY, 0);
        go.transform.localScale = scale;
        foreach (var r in go.GetComponentsInChildren<MeshRenderer>())
        {
            var mats = new Material[r.sharedMaterials.Length];
            for (int i = 0; i < mats.Length; i++) mats[i] = clay;
            r.sharedMaterials = mats;
        }
        return go;
    }

    static Material EnsureMat(string path, Color color)
    {
        Directory.CreateDirectory(Path.Combine(Application.dataPath, "Materials"));
        var mat = AssetDatabase.LoadAssetAtPath<Material>(path);
        if (mat == null)
        {
            mat = new Material(Shader.Find("Universal Render Pipeline/Lit"));
            AssetDatabase.CreateAsset(mat, path);
        }
        mat.SetColor("_BaseColor", color);
        mat.SetFloat("_Smoothness", 0.05f);
        mat.SetFloat("_Metallic", 0f);
        EditorUtility.SetDirty(mat);
        return mat;
    }

    static Color Hex(string hex)
    {
        ColorUtility.TryParseHtmlString(hex, out var c);
        return c;
    }

    // ------------------------------------------------------------- URP setup

    static void EnsureSSAO(string rendererPath)
    {
        var data = AssetDatabase.LoadAssetAtPath<ScriptableRendererData>(rendererPath);
        if (data == null) { Debug.LogWarning("Renderer data not found: " + rendererPath); return; }

        var feature = data.rendererFeatures
            .FirstOrDefault(f => f != null && f.GetType().Name == "ScreenSpaceAmbientOcclusion");

        if (feature == null)
        {
            var type = typeof(ScriptableRendererData).Assembly
                .GetType("UnityEngine.Rendering.Universal.ScreenSpaceAmbientOcclusion");
            if (type == null) { Debug.LogWarning("SSAO feature type not found in URP assembly."); return; }

            feature = (ScriptableRendererFeature)ScriptableObject.CreateInstance(type);
            feature.name = "ScreenSpaceAmbientOcclusion";
            AssetDatabase.AddObjectToAsset(feature, data);

            var so = new SerializedObject(data);
            var list = so.FindProperty("m_RendererFeatures");
            list.arraySize++;
            list.GetArrayElementAtIndex(list.arraySize - 1).objectReferenceValue = feature;
            var map = so.FindProperty("m_RendererFeatureMap");
            if (map != null)
            {
                map.arraySize++;
                AssetDatabase.TryGetGUIDAndLocalFileIdentifier(feature, out _, out long localId);
                map.GetArrayElementAtIndex(map.arraySize - 1).longValue = localId;
            }
            so.ApplyModifiedProperties();
            Debug.Log("[IsometricWorldBuilder] Added SSAO to " + rendererPath);
        }

        // Always (re)apply strong clay-render AO settings, even if it pre-existed.
        var fso = new SerializedObject(feature);
        SetFloat(fso, "m_Settings.Intensity", 1.7f);
        SetFloat(fso, "m_Settings.Radius", 0.5f);
        SetFloat(fso, "m_Settings.DirectLightingStrength", 0.55f);
        var falloff = fso.FindProperty("m_Settings.Falloff");
        if (falloff != null) falloff.floatValue = 120f;
        fso.ApplyModifiedProperties();
        EditorUtility.SetDirty(feature);
        EditorUtility.SetDirty(data);
        AssetDatabase.SaveAssets();
        Debug.Log("[IsometricWorldBuilder] SSAO settings applied to " + rendererPath);
    }

    static void SetFloat(SerializedObject so, string path, float value)
    {
        var p = so.FindProperty(path);
        if (p != null) p.floatValue = value;
    }

    static void ExtendShadowDistance(string rpAssetPath)
    {
        var rp = AssetDatabase.LoadAssetAtPath<UniversalRenderPipelineAsset>(rpAssetPath);
        if (rp == null) return;
        rp.shadowDistance = Mathf.Max(rp.shadowDistance, 120f);
        EditorUtility.SetDirty(rp);
    }
}
